  ('promotion-d592fc58-moex-00120', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '某甲獨資經營一家公司，創業資本來自其定期儲蓄存款到期後的 100 萬元，年利率為 5%。如果 該100萬元來自銀行貸款，且年利率也是5%，則就某甲而言，下列敘述何者正確？', '["其外顯成本（explicitcost）、內隱成本（implicitcost）與經濟成本（economiccost）都會增加", "其外顯成本會增加，內隱成本與經濟成本則都不變", "其外顯成本會增加，內隱成本會減少且經濟成本不變", "其外顯成本會減少，內隱成本與經濟成本則都會增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00121', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '假設商品X與Y為互補品且都合乎供給法則與需求法則。在其他條件不變下，當Y財的生產要 素價格上漲時，有關X財之敘述，下列何者正確？', '["均衡價格會上漲且人們對X財的支出金額會增加", "均衡價格會上漲且人們對X財的支出金額會減少", "均衡價格會下跌且人們對X財的支出金額會增加", "均衡價格會下跌且人們對X財的支出金額會減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00122', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '有關消費者預算線的斜率和無異曲線的斜率，下列敘述何者正確？', '["預算線的斜率為兩商品的相對價格，無異曲線的斜率為邊際替代率", "預算線的斜率為邊際替代率，無異曲線的斜率為兩商品的相對價格", "預算線的斜率和無異曲線的斜率皆為兩商品的相對價格", "預算線的斜率和無異曲線的斜率皆為邊際替代率 13550"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00123', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '有關恩格爾曲線（Engelcurve），下列敘述何者正確？', '["恩格爾曲線是刻劃當所得變動時，所有財貨的消費量如何隨之變動", "若某商品的需求函數符合需求法則，則其恩格爾曲線為正斜率", "奢侈品的恩格爾曲線是負斜率", "恩格爾曲線若為一垂直線，則該財貨必定不是季芬財"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00124', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '對於繪製一廠商之等產量曲線，下列關於廠商的假設何者正確？', '["廠商至少使用一種固定投入", "廠商追求利潤極大化", "廠商具有技術效率", "廠商具有經濟效率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00125', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', 'A、B兩家廠商生產相同的產品。A廠商的製造過程高度自動化，有大量的固定成本，而B廠商 的製造主要依賴變動要素。假設兩家廠商的銷售數字相當，下列敘述何者正確？', '["A廠商較快可以達到損益平衡點", "當產量越來越大，A廠商的利潤率可能越高於B廠商的利潤率", "A廠商的短期供給曲線較B廠商的短期供給曲線平緩", "A廠商的短期供給曲線較長期供給曲線較平緩"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00126', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '有關完全競爭市場，下列敘述何者錯誤？', '["個別廠商所面對的需求曲線為水平線", "廠商總是在平均成本最低點生產", "若廠商有超額利潤，市場的廠商數目會增加", "若勞動市場是完全競爭市場，價格等於邊際成本條件亦決定最適勞動僱用水準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00127', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '假設一獨占廠商面對之市場需求函數為 Q=9P，而成本函數為 C(Q)=2+Q2；其中 P 為價格，Q 為數量。若該公司可採行完全差別定價，則其最適產量為何？', '["3", "2.5", "2.25", "2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL)
